import threading

class Counter:
    def __init__(self):
        self.count = 0
    def increment(self):
        current = self.count
        self.count = current + 1

counter = Counter()
threads = [threading.Thread(target=counter.increment) for _ in range(1000)]
for t in threads: t.start()
for t in threads: t.join()
print(counter.get_count())
